2	`include "syn_tb_defines.vh"
3	
4	module csb_master_seq (
5	   clk,
6	   reset,
7	   
8	   mseq_pending_req,
9	   mcsb2mseq_consumed_req,
10	   mseq2mcsb_pd,
11	   mcsb2mseq_rdata,
12	   mcsb2mseq_rvalid,
13	
14	   dut2mseq_intr0,
15	   mseq2tb_test_done
16	);
17	
18	input clk;
19	input reset;
20	
21	output reg        mseq_pending_req;
22	input             mcsb2mseq_consumed_req;
23	output reg [62:0] mseq2mcsb_pd;
24	input      [31:0] mcsb2mseq_rdata;
25	input             mcsb2mseq_rvalid;
26	
27	input             dut2mseq_intr0;
28	output reg        mseq2tb_test_done;
29	
30	
31	
32	
33	parameter MSEQ_IDLE   = 8'h0;
34	parameter MSEQ_REG_RD = 8'h1;
35	parameter MSEQ_REG_RD_WAIT_RESP = 8'h2;
36	parameter MSEQ_REG_RD_POLL_WAIT = 8'h3;
37	parameter MSEQ_REG_RD_MISMATCH = 8'h4;
38	parameter MSEQ_REG_RD_TIMEOUT = 8'h5;
39	parameter MSEQ_REG_WR = 8'h8;
40	parameter MSEQ_REG_WR_WAIT_RESP = 8'h9;
41	parameter MSEQ_REG_WR_TIMEOUT = 8'ha;
42	parameter MSEQ_MEM_RD = 8'h10;
43	parameter MSEQ_MEM_WR = 8'h18;
44	parameter MSEQ_MEM_LD = 8'h20;
45	parameter MSEQ_MEM_DMP = 8'h28;
46	parameter MSEQ_WAIT = 8'h30;
47	parameter MSEQ_WAIT_TIMEOUT = 8'h31;
48	parameter MSEQ_BOOT_1 = 8'hfd;
49	parameter MSEQ_BOOT_2 = 8'hfe;
50	parameter MSEQ_DONE = 8'hff;
51	
52	parameter EQ = 8'h0;
53	parameter LE = 8'h1;
54	parameter GE = 8'h2;
55	
56	reg [`MSEQ_CMD_SIZE-1:0] cmd_memory[`MSEQ_NUM_CMDS-1:0];
57	reg [`MSEQ_CMD_SIZE-1:0] curr_cmd;
58	reg [`MSEQ_CONFIG_SIZE-1:0]               config_mem[`NUM_CONFIGS-1:0];
59	
60	wire [`MSEQ_OP_BITS]       curr_cmd_op;
61	wire [`MSEQ_DATA_BITS]     curr_cmd_data;
62	//wire [`MSEQ_MASK_BITS]     curr_cmd_mask;
63	// wire [`MSEQ_NPOLLS_BITS]   curr_cmd_polls;
64	// assign curr_cmd_polls   = curr_cmd[`MSEQ_NPOLLS_BITS];
65	// Make this wider and specified by the config file, not by the test file (despite the signal name)
66	reg [31:0]                 curr_cmd_polls;
67	assign curr_cmd_op      = curr_cmd[`MSEQ_OP_BITS];
68	assign curr_cmd_data    = curr_cmd[`MSEQ_DATA_BITS];
69	
70	
71	
72	reg [31:0] line;
73	reg [31:0] line_next;
74	reg  [7:0] cs, ns;
75	reg [`MSEQ_CONFIG_SIZE-1:0] timer;
76	reg [`MSEQ_CONFIG_SIZE-1:0] timer_next;
77	reg [`MSEQ_CONFIG_SIZE-1:0] count;
78	reg [`MSEQ_CONFIG_SIZE-1:0] count_next;
79	reg [31:0] response;
80	
81	reg [`MSEQ_MEM_ADDR_BITS] memory_start_address;
82	reg [`MSEQ_MEM_ADDR_BITS] memory_end_address;
83	reg dump_main_memory;
84	reg load_main_memory;
85	
86	// FIXME: Knobs?
87	reg [`MSEQ_CONFIG_SIZE-1:0] read_reg_poll_interval;
88	reg [`MSEQ_CONFIG_SIZE-1:0] read_timeout;
89	reg [`MSEQ_CONFIG_SIZE-1:0] write_timeout;
90	reg [`MSEQ_CONFIG_SIZE-1:0] wait_timeout;
91	reg        continue_on_fail;
92	
93	wire [31:0] boot_timer;
94	assign boot_timer = 10; //may not be needed
95	
96	// No x's
97	integer i;
98	//Change data size to a define
99	reg [31:0] rdata_no_x;
100	always @* begin
101	   for( i = 0; i < 32; i=i+1 ) begin
102	      if(mcsb2mseq_rdata[i]) rdata_no_x[i] = 1'b1; else rdata_no_x[i] = 1'b0;
103	   end
104	end
105	
106	initial begin //spyglass disable W430
107	   `ifdef ZEBU
108	      $readmemh("input.txn.zebu", cmd_memory); //spyglass disable W213
109	   `else
110	      $readmemh("input.txn.raw", cmd_memory); //spyglass disable W213
111	   `endif
112	   $readmemh("slave_mem.cfg", config_mem); //spyglass disable W213
113	end
114	
115	always @(posedge clk or negedge reset) begin
116	   if(!reset) begin
117	      cs <= MSEQ_BOOT_1;
118	      line <= 0;
119	      read_reg_poll_interval <= config_mem[`MSEQ_POLL_INTERVAL];
120	      read_timeout <= config_mem[`MSEQ_RD_TIMEOUT];
121	      write_timeout <= config_mem[`MSEQ_WR_TIMEOUT];
122	      write_timeout <= config_mem[`MSEQ_INTR_TIMEOUT];
123	      continue_on_fail <= config_mem[`MSEQ_CONT_ON_FAIL][0];
124	      curr_cmd_polls <= config_mem[`MSEQ_RD_POLLS];
125	      cs <= MSEQ_BOOT_1;
126	      line <= 0;
127	      count <= 0;
128	      timer <= 0;
129	   end else begin
130	      cs <= ns;
131	      line <= line_next;
132	      count <= count_next;
133	      timer <= timer_next;
134	   end
135	end
136	
137	// Calculate next state
138	always @* begin
139	   ns = cs;
140	   case(cs)
141	      MSEQ_IDLE : begin
142	         curr_cmd = cmd_memory[line];
143	         case(curr_cmd_op)
144	            `MSEQ_OP_DONE      : ns = MSEQ_DONE;
145	            `MSEQ_OP_REG_READ  : ns = MSEQ_REG_RD;
146	            `MSEQ_OP_REG_WRITE : ns = MSEQ_REG_WR;
147	            `MSEQ_OP_MEM_READ  : ns = MSEQ_MEM_RD;
148	            `MSEQ_OP_MEM_WRITE : ns = MSEQ_MEM_WR;
149	            `MSEQ_OP_MEM_LOAD  : ns = MSEQ_MEM_LD;
150	            `MSEQ_OP_MEM_DUMP  : ns = MSEQ_MEM_DMP;
151	            `MSEQ_OP_WAIT      : ns = MSEQ_WAIT;
152	         endcase
153	      end
154	      MSEQ_WAIT : begin
155	         if(dut2mseq_intr0 == 1)
156	            ns = MSEQ_IDLE;
157	         else begin
158	            if ( timer > wait_timeout ) begin
159	              ns = MSEQ_WAIT_TIMEOUT;
160	            end else begin
161	              ns = MSEQ_WAIT;
162	            end
163	         end
164	      end
165	      MSEQ_WAIT_TIMEOUT : begin
166	         if( continue_on_fail ) begin
167	            ns = MSEQ_IDLE;
168	         end else begin
169	            ns = MSEQ_DONE;
170	         end
171	      end
172	      MSEQ_REG_RD : begin
173	         if(count > curr_cmd_polls)
174	            ns = MSEQ_REG_RD_MISMATCH;
175	         else begin
176	            ns = MSEQ_REG_RD_WAIT_RESP;
177	         end
178	      end
179	      MSEQ_REG_RD_WAIT_RESP : begin
180	         if( timer > read_timeout )
181	            ns = MSEQ_REG_RD_TIMEOUT;
182	         else if( mcsb2mseq_rvalid ) begin
183	            response = rdata_no_x; 
184	            case( curr_cmd[`MSEQ_COMPARE_BITS] )
185	               EQ : begin
186	                  //TODO: mask
187	                  if( (rdata_no_x) == (curr_cmd_data) ) begin
188	                     ns = MSEQ_IDLE;
189	                  end else begin
190	                     ns = MSEQ_REG_RD_POLL_WAIT;
191	                  end
192	               end
193	               GE : begin
194	                  //TODO: mask
195	                  if( (rdata_no_x ) >= (curr_cmd_data ) ) begin
196	                     ns = MSEQ_IDLE;
197	                  end else begin
198	                     ns = MSEQ_REG_RD_POLL_WAIT;
199	                  end
200	               end
201	               LE : begin
202	                  //TODO: mask
203	                  if( (rdata_no_x ) <= (curr_cmd_data ) ) begin
204	                     ns = MSEQ_IDLE;
205	                  end else begin
206	                     ns = MSEQ_REG_RD_POLL_WAIT;
207	                  end
208	               end
209	            endcase
210	         end else
211	            ns = MSEQ_REG_RD_WAIT_RESP;
212	      end //MSEQ_REG_RD_WAIT_RESP
213	      MSEQ_REG_RD_POLL_WAIT : begin
214	         if(timer > read_reg_poll_interval)
215	            ns = MSEQ_REG_RD;
216	         else
217	            ns = MSEQ_REG_RD_POLL_WAIT;
218	      end
219	      MSEQ_REG_RD_MISMATCH : begin
220	         if( continue_on_fail ) begin
221	            ns = MSEQ_IDLE;
222	         end else begin
223	            ns = MSEQ_DONE;
224	         end
225	      end
226	      MSEQ_REG_RD_TIMEOUT : begin
227	         if( continue_on_fail ) begin
228	            ns = MSEQ_IDLE;
229	         end else begin
230	            ns = MSEQ_DONE;
231	         end
232	      end
233	      MSEQ_REG_WR : begin
234	         ns = MSEQ_REG_WR_WAIT_RESP;
235	      end
236	      MSEQ_REG_WR_WAIT_RESP : begin
237	         if( timer > write_timeout)
238	            ns = MSEQ_REG_WR_TIMEOUT;
239	         else if( mcsb2mseq_rvalid )
240	            //FIXME - do we care about the write status, or just that some response came back?
241	            ns = MSEQ_IDLE;
242	      end
243	      MSEQ_REG_WR_TIMEOUT : begin
244	         if( continue_on_fail ) begin
245	            ns = MSEQ_IDLE;
246	         end else begin
247	            ns = MSEQ_DONE;
248	         end
249	      end
250	      MSEQ_MEM_LD : begin
251	         ns = MSEQ_IDLE;
252	         //$readmemh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.syn_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - 32'h100_0000, (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - 32'h100_0000 - 1);
253	      end
254	      MSEQ_MEM_DMP : begin
255	         ns = MSEQ_IDLE;
256	         //$writememh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.syn_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - 32'h100_0000, (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - 32'h100_0000 - 1);
257	      end
258	      
259	      MSEQ_BOOT_1 : begin
260	         ns = MSEQ_BOOT_2;
261	      end
262	      MSEQ_BOOT_2 : begin
263	         if( timer > boot_timer )
264	            ns = MSEQ_IDLE;
265	         else
266	            ns = MSEQ_BOOT_2;
267	      end
268	      MSEQ_DONE : begin
269	         ns = MSEQ_DONE;
270	`ifdef ZEBU
271	         top.dollar_finish = 1'b1;
272	`else
273	         #500ns;
274	         $finish; //spyglass disable W213
275	`endif
276	      end
277	      default : begin
278	         if( reset ) begin
279	            $display("%0t MSEQ: ERROR: Unsupported command in master sequencer.", $time); //spyglass disable W213
280	            ns = MSEQ_DONE;
281	         end
282	      end
283	   endcase
284	end
285	
286	// Display debug/error info
287	always @(posedge clk) begin
288	   case(cs)
289	      MSEQ_REG_RD: begin
290	         if( count == 0 ) begin
291	            $display("%0t MSEQ: read_cmd address 0x%08x with data 0x%08x and mask 0x%08x (command %0d)", $time, curr_cmd[`MSEQ_ADDR_BITS], curr_cmd[`MSEQ_DATA_BITS], curr_cmd[`MSEQ_MASK_BITS], line - 5); //spyglass disable W213
292	         end
293	      end
294	      MSEQ_REG_WR: begin
295	         $display("%0t MSEQ: write_cmd address 0x%08x with data 0x%08x (command %0d)", $time, curr_cmd[`MSEQ_ADDR_BITS], curr_cmd[`MSEQ_DATA_BITS], line - 5); //spyglass disable W213
296	      end
297	      MSEQ_REG_RD_MISMATCH: begin
298	         if( continue_on_fail ) begin
299	            $display("%0t MSEQ: Read to address 0x%08x did not return the expected value 0x%08x after %0d attempts (last read 0x%08x), but continuing anyway.", 
300	                     $time, curr_cmd[`MSEQ_ADDR_BITS], curr_cmd[`MSEQ_DATA_BITS], curr_cmd[`MSEQ_NPOLLS_BITS], response); //spyglass disable W213
301	         end else begin
302	            $display("%0t MSEQ: ERROR: Read to address 0x%08x did not return the expected value 0x%08x after %0d attempts (last read 0x%08x), failing.", 
303	                     $time, curr_cmd[`MSEQ_ADDR_BITS], curr_cmd[`MSEQ_DATA_BITS], curr_cmd[`MSEQ_NPOLLS_BITS], response); //spyglass disable W213
304	         end
305	      end
306	      MSEQ_REG_RD_TIMEOUT: begin
307	         if( continue_on_fail ) begin
308	            $display("%0t MSEQ: Timed out waiting for register read on 0x%08x, continuing...", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
309	         end else begin
310	            $display("%0t MSEQ: ERROR: Timeout waiting for register read on 0x%08x, failing.", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
311	         end
312	      end
313	      MSEQ_REG_WR_TIMEOUT: begin
314	         if( continue_on_fail ) begin
315	            $display("%0t MSEQ: Timed out waiting for register write on 0x%08x, continuing...", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
316	         end else begin
317	            $display("%0t MSEQ: ERROR: Timeout waiting for register write on 0x%08x, failing.", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
318	         end
319	      end
320	      MSEQ_WAIT_TIMEOUT: begin
321	         if( continue_on_fail ) begin
322	            $display("%0t MSEQ: Timed out waiting for interrupt, continuing...", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
323	         end else begin
324	            $display("%0t MSEQ: ERROR: Timeout waiting for interrupt, failing.", $time, curr_cmd[`MSEQ_ADDR_BITS]); //spyglass disable W213
325	         end
326	      end
327	      MSEQ_REG_RD_POLL_WAIT: begin
328	         if( timer == 1 )
329	            $display("%0t MSEQ: Retrying read at 0x%08x (returned 0x%08x, expected 0x%08x)...", $time, curr_cmd[`MSEQ_ADDR_BITS], response, curr_cmd[`MSEQ_DATA_BITS]); //spyglass disable W213
330	      end
331	      MSEQ_REG_WR_WAIT_RESP : begin
332	         if( mcsb2mseq_rvalid )
333	            $display("%0t MSEQ: Write (command %0d) completed (addr: 0x%08x, data: 0x%08x.", $time, line - 5, curr_cmd[`MSEQ_ADDR_BITS], curr_cmd[`MSEQ_DATA_BITS]); //spyglass disable W213
334	      end
335	      MSEQ_REG_RD_WAIT_RESP : begin
336	         if( ns == MSEQ_IDLE )
337	            //Line - 5: -1 because line has advanced already, -5 more to negate the boot code automatically inserted in the test, and +1 so that we're using 1-based indexing.
338	            $display("%0t MSEQ: Read (command %0d) matched (addr: 0x%08x, received data: 0x%08x, expected data: 0x%08x.", $time, line - 5, curr_cmd[`MSEQ_ADDR_BITS], response, curr_cmd[`MSEQ_DATA_BITS]); //spyglass disable W213
339	         else if( ns == MSEQ_REG_RD_POLL_WAIT )
340	            $display("%0t MSEQ: Read mismatched, retrying (addr: 0x%08x, received data:  0x%08x, expected data: 0x%08x.", $time, curr_cmd[`MSEQ_ADDR_BITS], response, curr_cmd[`MSEQ_DATA_BITS]); //spyglass disable W213
341	      end
342	      MSEQ_MEM_LD : begin
343	         $display("%0t MSEQ: Backdoor mem_load of file %s at address 0x%08x for length 0x%08x.", $time, curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS], curr_cmd[`MSEQ_MEM_SIZE_BITS]);//spyglass disable W213
344	      end
345	      MSEQ_MEM_DMP : begin
346	         $display("%0t MSEQ: Backdoor mem_dump of file %s at address 0x%08x for length 0x%08x.", $time, curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS], curr_cmd[`MSEQ_MEM_SIZE_BITS]);//spyglass disable W213
347	      end
348	   endcase
349	end
350	
351	// Translate state machine to outputs
352	always @(posedge clk) begin
353	   if(!reset) begin
354	      mseq2tb_test_done <= 0;
355	   end else begin
356	      case(cs)
357	         MSEQ_BOOT_1: mseq2tb_test_done <= 0;
358	         MSEQ_IDLE: begin
359	            mseq2mcsb_pd <= 0;
360	            mseq_pending_req <= 0;
361	            mseq2tb_test_done <= 0;
362	            load_main_memory <= 0;
363	            dump_main_memory <= 0;
364	         end
365	         MSEQ_REG_RD: begin
366	            mseq_pending_req <= 1;
367	            mseq2mcsb_pd[62:55] <= curr_cmd[`MSEQ_PD_BITS];
368	            mseq2mcsb_pd[54] <= 0; //Reads set this bit to 0
369	            mseq2mcsb_pd[21:0] <= {6'b0,curr_cmd[`MSEQ_ADDR_PD_BITS]};
370	            mseq2mcsb_pd[53:22] <= curr_cmd[`MSEQ_DATA_PD_BITS];
371	         end
372	         MSEQ_REG_RD_WAIT_RESP: begin
373	            mseq_pending_req <= 0;
374	         // drop pd signals?
375	         end
376	         MSEQ_REG_WR: begin
377	            mseq_pending_req <= 1;
378	            mseq2mcsb_pd[62:55] <= curr_cmd[`MSEQ_PD_BITS];
379	            mseq2mcsb_pd[54] <= 1; //Writes set this bit to 1
380	            mseq2mcsb_pd[21:0] <= {6'b0,curr_cmd[`MSEQ_ADDR_PD_BITS]};
381	            mseq2mcsb_pd[53:22] <= curr_cmd[`MSEQ_DATA_PD_BITS];
382	         end
383	         MSEQ_REG_WR_WAIT_RESP: begin
384	            mseq_pending_req <= 0;
385	         // drop pd signals?
386	         end
387	         MSEQ_MEM_LD : begin
388	   `ifdef ZEBU
389	            // This will be handled by zemi3 xtor
390	   `elsif CADENCE
391	            //Loai: this command for 256bit memory as it needs -retainValue -retainValueOffset
392	            `ifdef MEM_WIDTH_32B
393	               if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
394	                 $qel("memory -load %%readmemh slave_mem_wrap.dbb_mem.memory -file %s -start %d -end %d -retainValue -retainValueOffset",curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM));
395	               end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
396	                 $qel("memory -load %%readmemh slave_mem_wrap.cvsram_mem.memory -file %s -start %d -end %d -retainValue -retainValueOffset",curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM));
397	              end
398	            `else
399	               if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
400	                 $readmemh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.dbb_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM));
401	               end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
402	                 $readmemh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.cvsram_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM));
403	               end else
404	                 $display("Error: Address in input.txn for loading file to memory is outside defined regions, DBB_ADDR_START or CSVRAM_ADDR_START");
405	                 $finish;
406	               end
407	             `endif
408	   `else
409	              `ifndef SPYGLASS
410	            //e.g load_mem 0x80000000 0x400 sample_surf.dat
411	            // if sample_surf.dat is first file loaded it turns into 0.raw2
412	            // 0.raw2 is read through curr_cmd[`MSEQ_FILENAME_BITS]
413	            // putting it into top.slave_mem_wrap.dbb_mem.memory
414	            // curr_cmd[MSEQ_MEM_ADDR_BITS=80000000] MEM_BYTES=MEM_WIDTH/8=32/8=4
415	            // DBB_ADDR_START=0x80000000 LOG2_MEM=log2(MEM_WIDTH)-3=5-3=2
416	            // 3rd arguments = 80000000/4 - (0x80000000 >> 2) = 0
417	            // size (4th arg) = 3rd arg + 0x400/4 - 1 = 0xff
418	            if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
419	              $readmemh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.dbb_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM));
420	            end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
421	              $readmemh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.cvsram_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM));
422	            end
423	              `endif
424	   `endif
425	            if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
426	              memory_start_address <= curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM);
427	              memory_end_address <= (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM) - 1;
428	              load_main_memory <= 1;
429	            end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
430	              memory_start_address <= curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM);
431	              memory_end_address <= (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM) - 1;
432	              load_main_memory <= 1;
433	            end
434	         end
435	         MSEQ_MEM_DMP : begin
436	   `ifdef EMU_TB
437	            // This will be handled by zemi3 xtor
438	   `else
439	            if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
440	                $writememh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.dbb_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM));
441	            end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
442	                $writememh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.cvsram_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM));
443	            end
444	   `endif
445	            if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
446	                memory_start_address <= curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM);
447	                memory_end_address <= (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM) - 1;
448	                dump_main_memory <= 1;
449	            end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
450	                memory_start_address <= curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM);
451	                memory_end_address <= (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM) - 1;
452	                dump_main_memory <= 1;
453	            end
454	         end
455	         
456	         MSEQ_DONE: begin
457	            mseq2mcsb_pd <= 0;
458	            mseq2tb_test_done <= 1;
459	         end
460	         default : begin
461	            mseq2mcsb_pd <= 1'bx;
462	            mseq2tb_test_done <= 1'bx;
463	         end
464	      endcase
465	   end
466	end
467	
468	`ifdef CADENCE
469	always @(posedge clk) begin
470	   if (cs == MSEQ_MEM_DMP) begin
471	      //Loai: this command for 256bit memory as it needs -retainValue -retainValueOffset for memory load
472	      `ifdef MEM_WIDTH_32B
473	          if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
474	             $qel("memory -dump %%readmemh slave_mem_wrap.dbb_mem.memory -file %s -start %d -end %d", curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM));
475	          end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
476	             $qel("memory -dump %%readmemh slave_mem_wrap.cvsram_mem.memory -file %s -start %d -end %d", curr_cmd[`MSEQ_FILENAME_BITS], curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS] - 1)/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM));
477	         end
478	      `else
479	         //Everything up to the least significant 1 of ADDR_START should be 0 in the mask
480	         if ((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `DBB_ADDR_START) begin
481	             $writememh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.dbb_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`DBB_ADDR_START >> `LOG2_MEM) - 1);
482	         end else if((curr_cmd[`MSEQ_MEM_ADDR_BITS] & `DLA_ADDR_MASK) == `CVSRAM_ADDR_START) begin
483	             $writememh(curr_cmd[`MSEQ_FILENAME_BITS], top.slave_mem_wrap.cvsram_mem.memory, curr_cmd[`MSEQ_MEM_ADDR_BITS]/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM), (curr_cmd[`MSEQ_MEM_ADDR_BITS] + curr_cmd[`MSEQ_MEM_SIZE_BITS])/(`MEM_BYTES) - (`CVSRAM_ADDR_START >> `LOG2_MEM) - 1);
484	         end
485	         //dump_main_memory <= 1;
486	      `endif
487	   end
488	end
489	`endif
490	
491	// Run timers
492	// Review the following case statement : Might have missing cases. Currently requires the default.
493	always @* begin
494	      line_next  = line;
495	      count_next = count;
496	      timer_next = timer;
497	 
498	   if( !reset ) begin
499	      line_next  = 0;
500	      count_next = 0;
501	      timer_next = 0;
502	   end else begin
503	      case(cs)
504	         MSEQ_IDLE: begin
505	            line_next = line + 1;
506	            count_next = 0;
507	         end
508	         MSEQ_REG_RD: begin
509	            count_next = count + 1;
510	            timer_next = 0;
511	         end
512	         MSEQ_REG_RD_WAIT_RESP: begin
513	            if((timer <= read_timeout) && mcsb2mseq_rvalid)
514	               timer_next = 0;
515	            else
516	               timer_next = timer + 1;
517	         end
518	         MSEQ_REG_RD_POLL_WAIT: begin
519	            timer_next = timer + 1;
520	         end
521	         MSEQ_REG_WR: begin
522	            timer_next = 0;
523	         end
524	         MSEQ_REG_WR_WAIT_RESP: begin
525	            timer_next = timer + 1;
526	         end
527	         MSEQ_WAIT: begin
528	            if((timer <= read_timeout) && dut2mseq_intr0)
529	               timer_next = 0;
530	            else
531	               timer_next = timer + 1;
532	         end
533	         MSEQ_BOOT_1: begin
534	            timer_next = 0;
535	         end
536	         MSEQ_BOOT_2: begin
537	            timer_next = timer + 1;
538	         end
539	         default: begin
540	            line_next  = line;
541	            count_next = count;
542	            timer_next = timer;
543	         end
544	      endcase
545	   end
546	end
547	
548	endmodule
